import sailpoint.object.QueryOptions;
import sailpoint.object.Filter;
import sailpoint.object.Identity;




QueryOptions options = new QueryOptions();
QueryOptions woptions = new QueryOptions();
Filter filter = Filter.and(Filter.eq("workgroup",false),Filter.isempty("links"));
options.addFilter(filter);
woptions.addFilter(Filter.eq("workgroup",true));

List identities = context.getObjects(Identity.class,options);
List workGroups = context.getObjects(Identity.class,woptions);

try{
  if(identities!=null && workGroups!=null){
    for (Identity identityObj : identities){
      log.error("Iterating Identity : "+identityObj.getName());
      for(Identity workGroup : workGroups){

        boolean isMember=identityObj.isInWorkGroup(workGroup);
        if(isMember){
          identityObj.remove(workGroup);
          log.error("Removed Identity : "+identityObj.getName()+" from workGroup : "+workGroup.getName());
        }
      }
    }
  }
}catch(Exception e){
  log.error("An exception occurred while removing the No Links identity from the WorkGroup rule: "+e.getMessage());
}finally{
  context.commitTransaction();
}
return identities.size()+" NoLinks Identities have been removed from "+workGroups.size()+ " Workgroups";










